import Foundation

func solve(n: Int64) -> Bool {
    var num = n
    var sum: Int64 = 0
    var product: Int64 = 1

    // Handle the case where n is 0, though n is positive per problem statement
    if num == 0 {
        return false
    }

    // Calculate sum and product of digits
    var temp = num
    while temp != 0 {
        let digit = temp % 10
        sum += digit
        product *= digit
        temp /= 10
    }

    // Check if the sum of sum and product is zero to avoid division by zero
    let total = sum + product
    if total == 0 {
        return false
    }

    // Check if n is divisible by the total
    return n % total == 0
}
